#include <bits/stdc++.h>
using namespace std;
int dp[31][20004];
int main(){
    int v,n,a[31];
    cin>>v>>n;
    for(int i=1;i<=n;i++)
        for(int j=0;j<=v;j++)dp[i][j]=0;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=n;i++)
        for(int j=1;j<=v;j++)
            dp[i][j]=(j<a[i]?max(dp[i][j],dp[i-1][j]):max(max(dp[i-1][j],dp[i][j]),dp[i-1][j-a[i]]+a[i]));
    /*for(int i=1;i<=n;i++){
    	for(int j=1;j<=v;j++)
    		printf("%d ",dp[i][j]);
    	printf("\n");
	}*/
    cout<<v-dp[n][v];
    return 0;
}
